class Solution(object):
    def numEquivDominoPairs(self, dominoes):
        from collections import Counter
        count = 0
        dom_count = {}
        for dom in dominoes:
            key = tuple(sorted(dom))
            count += dom_count.get(key, 0)
            dom_count[key] = dom_count.get(key, 0) + 1
        return count
